function rotateMultipleChoice(question, offset) {
  if (question.type !== "mc") return question;
  const shift = offset % question.options.length;
  return {
    ...question,
    options: [...question.options.slice(shift), ...question.options.slice(0, shift)],
    answer: (question.answer - shift + question.options.length) % question.options.length
  };
}

for (const chapter of chapters) {
  const additions = supplementalQuestions[chapter.id].map((question, index) =>
    rotateMultipleChoice(question, index + Number(chapter.id))
  );
  chapter.questions.push(...additions);
}

export const chapterById = (id) => chapters.find((chapter) => chapter.id === String(id));
